insert into survey_instances (survey_instance_id, company_id, onboarding_id,
  survey_template_id, scheduled_at, sent_at,
  closed_at, status, created_at ,  responder_user_id
  )
values (#{surveyInstanceId,jdbcType=VARCHAR}, #{companyId,jdbcType=VARCHAR}, #{onboardingId,jdbcType=VARCHAR},
  #{surveyTemplateId,jdbcType=VARCHAR}, #{scheduledAt,jdbcType=TIMESTAMP}, #{sentAt,jdbcType=TIMESTAMP},
  #{closedAt,jdbcType=TIMESTAMP}, #{status,jdbcType=VARCHAR}, #{createdAt,jdbcType=TIMESTAMP},#{responderUserId,jdbcType=VARCHAR}
  )

mapper.select:
select
survey_instance_id  as "surveyInstanceId",
survey_template_id  as "surveyTemplateId",
onboarding_id       as "onboardingId",
status              as "status",
sent_at             as "sentAt",
closed_at           as "closedAt"
from survey_instances
where company_id = #{companyId}

  and survey_template_id = #{templateId}


  and onboarding_id = #{onboardingId}


  and status = #{status}

order by sent_at desc

SELECT si.survey_instance_id AS surveyInstanceId, si.survey_template_id AS surveyTemplateId, st.name AS templateName, si.scheduled_at AS scheduledAt, si.status AS status, si.created_at AS createdAt,
si.onboarding_id AS onboardingId, si.responder_user_id AS responderUserId, u.full_name AS employeeName, u.email AS email
FROM survey_instances si
LEFT JOIN users u ON si.responder_user_id = u.user_id
LEFT JOIN survey_templates st ON si.survey_template_id = st.survey_template_id
WHERE si.company_id = #{companyId}
AND si.survey_template_id = #{templateId}
AND si.status = #{status}
AND si.created_at >= #{startDate}
AND si.created_at <= #{endDate}
ORDER BY si.created_at DESC LIMIT #{limit} OFFSET #{offset}
